#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/*
 * Greedy algorithm to pick K digits from a string of length n (in order)
 * to maximize the resulting K-digit number.
 *
 * For position k (0-indexed, picking K total digits):
 *   - We must pick one digit from indices [start .. n - (K - k)]
 *     (leaving enough digits for the remaining K-k-1 picks after)
 *   - Pick the maximum digit in that range.
 *   - If there are ties, pick the leftmost (earliest) occurrence of the max
 *     so we leave maximum freedom for later digits... wait, actually for
 *     maximizing a number, we want max at each position. If there are ties
 *     at position k, picking earlier leaves more room for later positions,
 *     which is better. So pick the FIRST occurrence of max in the range.
 *
 * Store the selected digits in result (null-terminated string of K digits).
 */
static void best_k_digits(const char *s, int n, int K, char *result) {
    int start = 0;
    for (int k = 0; k < K; k++) {
        /* remaining picks after this one: K - k - 1 */
        int remaining = K - k - 1;
        /* can pick from start .. n - 1 - remaining */
        int end = n - 1 - remaining;
        /* find max digit in s[start..end] */
        char best = '0';
        for (int i = start; i <= end; i++) {
            if (s[i] > best) best = s[i];
        }
        /* find first occurrence of best in [start..end] */
        int chosen = start;
        for (int i = start; i <= end; i++) {
            if (s[i] == best) { chosen = i; break; }
        }
        result[k] = s[chosen];
        start = chosen + 1;
    }
    result[K] = '\0';
}

int main(int argc, char *argv[]) {
    int part = 0;
    if (argc >= 2) part = atoi(argv[1]);

    FILE *f = fopen("input.txt", "r");
    if (!f) { fprintf(stderr, "Cannot open input.txt\n"); return 1; }

    long long total1 = 0, total2 = 0;

    char line[4096];
    while (fgets(line, sizeof(line), f)) {
        /* strip newline */
        int n = (int)strlen(line);
        while (n > 0 && (line[n-1] == '\n' || line[n-1] == '\r')) n--;
        if (n == 0) continue;
        line[n] = '\0';

        /* Part 1: pick 2 digits */
        if (n >= 2) {
            char res1[3];
            best_k_digits(line, n, 2, res1);
            long long val1 = (res1[0] - '0') * 10 + (res1[1] - '0');
            total1 += val1;
        }

        /* Part 2: pick 12 digits */
        if (n >= 12) {
            char res2[13];
            best_k_digits(line, n, 12, res2);
            /* parse 12-digit number */
            long long val2 = 0;
            for (int i = 0; i < 12; i++) {
                val2 = val2 * 10 + (res2[i] - '0');
            }
            total2 += val2;
        }
    }

    fclose(f);

    if (part == 1 || part == 0) printf("Part 1: %lld\n", total1);
    if (part == 2 || part == 0) printf("Part 2: %lld\n", total2);

    return 0;
}

