static int read_line(FILE *f, char **buf, size_t *cap) {
    size_t len = 0;
    int c;
    while ((c = fgetc(f)) != EOF) {
        if (c == '\n') break;
        if (c == '\r') continue; /* skip CR in CRLF */
        /* ensure capacity */
        if (len + 2 > *cap) {
            size_t newcap = (*cap == 0) ? 1024 : (*cap * 2);
            char *newbuf = realloc(*buf, newcap);
            if (!newbuf) { fprintf(stderr, "OOM\n"); exit(1); }
